require('dotenv').config();
const fs = require('fs');
const path = require('path');
const mongoose = require('mongoose');
const { SPELLING_BEE_WORDS } = require('./lib/spellingBeeWords');

/** Extra 5-letter words generated by `node scripts/build-seed-word-bank.js` (gitignored optional; empty file ok) */
function loadServerdleWordBank() {
    const p = path.join(__dirname, 'data', 'serverdle-word-bank.txt');
    if (!fs.existsSync(p)) return [];
    return fs
        .readFileSync(p, 'utf8')
        .split(/\n/)
        .map((l) => l.trim().toUpperCase())
        .filter((w) => /^[A-Z]{5}$/.test(w));
}

